INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                          
                             
                               
                             
     O Banco de Portugal pode determinar, por regulamentação, os termos em que sujeita as sociedades financeiras aos requisitos do título VII-A.            
         
   
     
                         
                          
